<?php require_once '../config/db.php'; if(!isLoggedIn()) redirect('admin/login.php'); $categories=$pdo->query("SELECT * FROM categories")->fetchAll(); if($_POST){ $name=$_POST['name']; $category_id=$_POST['category_id']; $desc=$_POST['description']; $price=$_POST['price']; $stock=$_POST['stock']; $slug=strtolower(trim(preg_replace('/[^A-Za-z0-9-]+/', '-', $name))); $image='default-product.jpg'; $stmt=$pdo->prepare("INSERT INTO products (category_id,name,slug,description,price,stock_quantity,image) VALUES (?,?,?,?,?,?,?)"); $stmt->execute([$category_id,$name,$slug,$desc,$price,$stock,$image]); redirect('admin/products.php'); } include 'includes/admin_header.php'; ?>
<div class="container"><h2>Add Product</h2><form method="POST"><div class="mb-3"><label>Name</label><input name="name" class="form-control" required></div><div class="mb-3"><label>Category</label><select name="category_id" class="form-control"><?php foreach($categories as $c){ echo "<option value='{$c['id']}'>{$c['name']}</option>"; } ?></select></div><div class="mb-3"><label>Description</label><textarea name="description" class="form-control"></textarea></div><div class="mb-3"><label>Price (₦)</label><input type="number" step="0.01" name="price" class="form-control"></div><div class="mb-3"><label>Stock</label><input type="number" name="stock" class="form-control"></div><button class="btn btn-primary">Save</button></form></div>
<?php include 'includes/admin_footer.php'; ?>